            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] === this.rank[yRoot]) {
                    this.rank[xRoot]++;
                }
            }
            return true;
        }

        count() {
            let count = 0;
            for (let i = 0; i < this.parent.length; i++) {
                if (this.find(i) === i) count++;
            }
            return count;
        }
    }

    function check(t) {
        const uf = new UnionFind(n);
        for (const [u, v, time] of edges) {
            if (time > t) {
                uf.union(u, v);
            }
        }
        return uf.count() >= k;
    }

    let left = 0, right = max_time;
    let answer = max_time;

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        if (check(mid)) {
            answer = mid;
            right = mid - 1;
